constexpr ll mod = 1000000007;



ll modpow(ll a, ll n, ll m) {

	ll res = 1;

	while (n) {

		if (n & 1)res = res * a % m;

		a = a * a%m; n >>= 1;

	}

	return res;

}



void solve(){

  int n, k; cin >> n >> k;

  ll lw = 1, up = 1, ans = 0;



  FOR(i,k,n+2){

    lw = ((ll)(i-1)*i%mod) * modpow(2,mod-2,mod)%mod;//couts(lw);

